class BloomFilter:
    def __init__(self, m: int, k: int):
        self.m = m
        self.k = k
        self.bits = [False] * m

    def _hashes(self, element):
        return [hash((element, seed)) % self.m for seed in range(self.k)]

    def add(self, element) -> None:
        for idx in self._hashes(element):
            self.bits[idx] = True

    def contains(self, element) -> bool:
        return all(self.bits[idx] for idx in self._hashes(element))

